/* src/input.c */
#include <stdio.h>
#include <string.h>

#define BUF_SIZE 64

char global_buf[BUF_SIZE];

void read_user_input(void) {
    char local_buf[BUF_SIZE];
    printf("Enter command: ");
    gets(local_buf);  /* line 15: CWE-120 buffer overflow - no bounds check */
    strncpy(global_buf, local_buf, BUF_SIZE - 1);
    global_buf[BUF_SIZE - 1] = '\0';
}

void copy_safe(const char *src, size_t src_len) {
    char dest[128];
    /* line 30: SAFE - memcpy bounded by sizeof(dest) and src_len */
    size_t copy_len = (src_len < sizeof(dest)) ? src_len : sizeof(dest) - 1;
    memcpy(dest, src, copy_len);
    dest[copy_len] = '\0';
}
